4	public actor UsagesFileManager {
5	    // Internal init so tests can create isolated instances via @testable import.
6	    // Production code must use `UsagesFileManager.shared`.
7	    public static let shared = UsagesFileManager()
8	
9	    nonisolated public let filePath: String
10	    nonisolated public let lockPath: String
11	    private let logger: FileLogger
