15	        filePath: String? = nil,
16	        logger: FileLogger = Loggers.app,
17	        lockTimeoutSeconds: TimeInterval = 5.0
18	    ) {
19	        let home = FileManager.default.homeDirectoryForCurrentUser.path
20	        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
21	        self.logger = logger
22	        self.lockPath = self.filePath + ".lock"
23	        self.lockTimeoutSeconds = lockTimeoutSeconds
