26	        do {
27	            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
28	        } catch {
29	            logger.log(.error, "Failed to create directory \(dir): \(error)")
30	        }
31	    }
32	
33	    // MARK: - Public
34	
35	    public func read() async -> UsagesFile {
36	        do {
37	            return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
38	        } catch is CancellationError {
39	            return UsagesFile()
40	        } catch {
41	            logger.log(.warning, "flock read failed — returning empty file: \(error)")
42	            return UsagesFile()
43	        }
44	    }
45	
46	    public func update(with entries: [VendorUsageEntry]) async {
47	        do {
48	            try await withFileLock(mode: LOCK_EX) {
49	                var file = readUnsafe()
50	                file = merge(existing: file, incoming: entries)
51	                writeUnsafe(file)
52	            }
53	        } catch is CancellationError {
54	            return
55	        } catch {
56	            logger.log(.warning, "flock update failed — skipping write: \(error)")
57	        }
58	    }
59	
60	    // MARK: - Active-account update
61	
62	    public func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) async {
63	        do {
64	            try await withFileLock(mode: LOCK_EX) {
65	                var file = readUnsafe()
66	                var changed = false
67	                for i in file.usages.indices {
68	                    guard file.usages[i].vendor == vendor else { continue }
69	                    let newActive = file.usages[i].account == activeAccount
70	                    if file.usages[i].isActive != newActive {
71	                        file.usages[i].isActive = newActive
72	                        changed = true
73	                    }
74	                }
75	                if changed {
76	                    writeUnsafe(file)
77	                }
78	            }
79	        } catch is CancellationError {
80	            return
81	        } catch {
82	            logger.log(.warning, "flock updateIsActive failed — skipping: \(error)")
83	        }
84	    }
85	
86	    // MARK: - Merge logic
87	
88	    func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
89	        var usages = existing.usages
90	        var indexByKey: [String: Int] = [:]
91	        for (i, entry) in usages.enumerated() {
92	            indexByKey["\(entry.vendor.rawValue)|\(entry.account.rawValue)"] = i
93	        }
94	        for entry in incoming {
95	            let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
96	            if let idx = indexByKey[key] {
97	                if entry.lastError != nil {
98	                    // Errors must not erase previously acquired data: the file may hold good
99	                    // metrics from a prior successful fetch while the connector's in-memory
100	                    // lastKnownMetrics is empty (e.g. after an app restart).
101	                    var merged = entry
102	                    if merged.metrics.isEmpty {
103	                        merged.metrics = usages[idx].metrics
104	                    }
105	                    if merged.lastAcquiredOn == nil {
106	                        merged.lastAcquiredOn = usages[idx].lastAcquiredOn
107	                    }
108	                    usages[idx] = merged
109	                } else {
110	                    usages[idx] = entry
111	                }
112	            } else {
113	                indexByKey[key] = usages.count
114	                usages.append(entry)
115	            }
116	        }
117	        return UsagesFile(usages: usages)
118	    }
119	
120	    // MARK: - Lock-guarded internals
121	
122	    /// Acquires an advisory flock on the dedicated lock file, runs `body`, then releases.
123	    /// Uses a separate lock file because atomic writes replace the JSON inode, making
124	    /// flock on the data file itself ineffective for protecting external readers.
125	    private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
126	        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
127	        guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
128	        defer { Darwin.close(fd) }
129	
130	        let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
131	        while flock(fd, mode | LOCK_NB) != 0 {
132	            guard Date() < deadline else {
133	                throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
134	            }
135	            try await Task.sleep(for: .milliseconds(50))
136	        }
137	        defer { flock(fd, LOCK_UN) }
138	
139	        return try body()
140	    }
141	
142	    // MARK: - Unsafe (actor-isolated, no external lock needed)
143	
144	    private func readUnsafe() -> UsagesFile {
145	        guard let data = FileManager.default.contents(atPath: filePath) else {
146	            return UsagesFile()
147	        }
148	        do {
149	            return try JSONDecoder().decode(UsagesFile.self, from: data)
150	        } catch {
151	            logger.log(.error, "Failed to decode \(filePath): \(error)")
152	            return UsagesFile()
153	        }
154	    }
155	
156	    private func writeUnsafe(_ file: UsagesFile) {
157	        let encoder = JSONEncoder()
158	        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
159	        guard let data = try? encoder.encode(file) else {
160	            logger.log(.error, "Failed to encode usages file")
161	            return
162	        }
163	        do {
164	            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
165	        } catch {
166	            logger.log(.error, "Atomic write failed: \(error)")
167	            return
168	        }
169	        logger.log(.debug, "Wrote usages file to \(filePath)")
170	    }
171	}
172	
173	enum FileManagerError: Error, CustomStringConvertible {
174	    case cannotOpenLockFile(path: String)
175	    case lockTimeout(path: String, timeoutSeconds: Double)
176	
177	    var description: String {
178	        switch self {
179	        case let .cannotOpenLockFile(path):
180	            "Cannot open lock file at \(path)"
181	        case let .lockTimeout(path, secs):
182	            "Could not acquire flock on \(path) within \(secs)s"
183	        }
184	    }
185	}
