import Foundation

// MARK: - Async polling helper

struct EventuallyTimeoutError: Error, CustomStringConvertible {
    let timeout: TimeInterval
    var description: String { "Condition not met within \(timeout)s" }
}

/// Polls `condition` on the main actor at `interval` until it returns true or `timeout` expires.
@MainActor
func eventually(
    timeout: TimeInterval = 2.0,
    interval: TimeInterval = 0.01,
    _ condition: @MainActor () -> Bool
) async throws {
    let deadline = Date(timeIntervalSinceNow: timeout)
    while true {
        if condition() { return }
        guard Date() < deadline else { throw EventuallyTimeoutError(timeout: timeout) }
        try await Task.sleep(for: .seconds(interval))
    }
}

/// Non-isolated overload for tests that need `await` inside the condition
/// (e.g. reading actor-isolated properties).
func eventually(
    timeout: TimeInterval = 2.0,
    interval: TimeInterval = 0.01,
    _ condition: @escaping @Sendable () async -> Bool
) async throws {
    let deadline = Date(timeIntervalSinceNow: timeout)
    while true {
        if await condition() { return }
        guard Date() < deadline else { throw EventuallyTimeoutError(timeout: timeout) }
        try await Task.sleep(for: .seconds(interval))
    }
}

// MARK: - Absence-confirmation delay

/// Absence-confirmation tests have no observable state to poll, so they wait a
/// fixed duration. A shared constant avoids repeating the rationale at each call site.
let absenceConfirmationDelay: Duration = .milliseconds(100)

import Darwin
import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("UsagesFileManager")
struct UsagesFileManagerTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-tests-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private func makeManager(dir: String) -> UsagesFileManager {
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        // Uses the internal init accessible via @testable import — production code uses .shared.
        return UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
    }

    @Test("read returns empty file when no file exists")
    func readMissing() async {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let result = await mgr.read()
        #expect(result.usages.isEmpty)
    }

    @Test("update creates file and writes entries")
    func updateCreatesFile() async {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let entry = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T15:00:00+00:00",
                        windowDuration: 300, usagePercent: 50),
