3	// MARK: - Protocol (injectable for tests)
4	
5	public protocol FileWatching: Sendable {
6	    func changes() -> AsyncStream<Data>
7	}
8	
9	// MARK: - Production implementation
10	
11	/// Watches a single file using FS events (DispatchSource) with a polling fallback.
12	///
13	/// Hybrid strategy: a `DispatchSource.makeFileSystemObjectSource` watches for
14	/// `.write` events. A fallback timer re-checks every `pollInterval` seconds in
15	/// case FS events are missed (network mounts, fd invalidation after atomic
16	/// replace). Duplicate reads are suppressed by comparing modification dates.
17	public final class UsagesFileWatcher: FileWatching, Sendable {
18	    private let path: String
19	    private let pollInterval: TimeInterval
20	    private let logger: FileLogger
21	
22	    public static let defaultPollSeconds: TimeInterval = 30
23	
24	    public init(
25	        path: String,
26	        pollInterval: TimeInterval = UsagesFileWatcher.defaultPollSeconds,
27	        logger: FileLogger = Loggers.app
28	    ) {
29	        self.path = path
30	        self.pollInterval = pollInterval
31	        self.logger = logger
32	    }
33	
34	    public func changes() -> AsyncStream<Data> {
35	        let path = self.path
36	        let pollInterval = self.pollInterval
37	        let logger = self.logger
38	
39	        return AsyncStream { continuation in
40	            let watcherTask = Task {
41	                // Protects lastModDate from concurrent access (GCD handler + cooperative pool)
42	                let lock = NSLock()
43	                var lastModDate: Date?
44	                var dispatchSource: DispatchSourceFileSystemObject?
45	                var fileDescriptor: Int32 = -1
46	                // Prevents repeated warnings when the file stays unreadable across poll ticks
47	                var contentReadFailed = false
48	
49	                func emitIfChanged() {
50	                    lock.lock()
51	                    defer { lock.unlock() }
52	
53	                    let attrs: [FileAttributeKey: Any]
54	                    do {
55	                        attrs = try FileManager.default.attributesOfItem(atPath: path)
56	                    } catch {
57	                        if !contentReadFailed {
58	                            logger.log(.warning, "FileWatcher: attributesOfItem failed on \(path): \(error)")
59	                            contentReadFailed = true
60	                        }
61	                        return
62	                    }
63	                    guard let modDate = attrs[.modificationDate] as? Date else {
64	                        return
65	                    }
66	                    if modDate != lastModDate {
67	                        if let data = FileManager.default.contents(atPath: path) {
68	                            lastModDate = modDate
69	                            contentReadFailed = false
70	                            continuation.yield(data)
71	                        } else {
72	                            if !contentReadFailed {
73	                                logger.log(.warning, "FileWatcher: contents(atPath:) returned nil for \(path)")
74	                                contentReadFailed = true
75	                            }
76	                        }
77	                    }
78	                }
79	
80	                func openSource() -> (DispatchSourceFileSystemObject, Int32)? {
81	                    let fd = open(path, O_EVTONLY)
82	                    guard fd >= 0 else {
83	                        logger.log(.warning, "FileWatcher: open() failed on \(path): \(String(cString: strerror(errno)))")
84	                        return nil
85	                    }
86	                    // If cancelled before resume(), the cancel handler won't fire — guard against fd leak
87	                    guard !Task.isCancelled else {
88	                        close(fd)
89	                        return nil
90	                    }
91	                    let source = DispatchSource.makeFileSystemObjectSource(
92	                        fileDescriptor: fd,
93	                        eventMask: [.write, .delete, .rename],
94	                        queue: DispatchQueue.global(qos: .utility)
95	                    )
96	                    source.setEventHandler { emitIfChanged() }
97	                    source.setCancelHandler { close(fd) }
98	                    source.resume()
99	                    return (source, fd)
100	                }
101	
102	                emitIfChanged()
103	
104	                if let (src, fd) = openSource() {
105	                    dispatchSource = src
106	                    fileDescriptor = fd
107	                    logger.log(.debug, "FileWatcher: FS events active on \(path)")
108	                } else {
109	                    logger.log(.warning, "FileWatcher: FS source unavailable on \(path), using poll-only mode")
110	                }
111	
112	                while !Task.isCancelled {
113	                    // CancellationError swallowed intentionally; checked on next loop iteration
114	                    // Cap at ~292 years to prevent UInt64 overflow for large pollInterval values
115	                    let maxNanos: Double = Double(UInt64.max)
116	                    let refreshNanos = UInt64(min(pollInterval * 1_000_000_000, maxNanos))
117	                    try? await Task.sleep(nanoseconds: refreshNanos)
118	                    guard !Task.isCancelled else { break }
119	
120	                    emitIfChanged()
121	
122	                    // Re-establish FS watcher if fd went stale (file was replaced).
123	                    // fcntl(F_GETFD) only checks the fd is open, not that it still refers to
124	                    // the file at `path`. After an atomic rename the old fd stays open (valid)
125	                    // but points to the displaced inode, so FS events for the new file are
126	                    // missed until the next poll. Inode comparison catches this case.
