        ])
        watcher.send(data)
        try await eventually { store.menuBarText == "5 42% 3h" }
        #expect(store.menuBarText == "5 42% 3h")

        // Advance clock forward — countdown should drop to the next lower whole-hour bucket
        clock.date = f.date(from: "2026-04-17T13:00:00Z")!
        try await eventually(timeout: 3.0) { store.menuBarText == "5 42% 2h" }
        #expect(store.menuBarText == "5 42% 2h")
        store.stop()
    }

