          "vendors": {
            "claude": {
              "accounts": [
                {"account":"a@b.com","isActive":true,"metrics":[]}
              ],
              "outages": [
                {"id":"inc-1","title":"API issues","severity":"major"}
              ]
            }
          }
        }
